export const getAdminListCommitsUrl = (params?: AdminListCommitsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/commits?${stringifiedParams}`
    : `/api/admin/commits`;
};

export const adminListCommits = async (
  params?: AdminListCommitsParams,
  options?: RequestInit,
): Promise<CommitSummary[]> => {
  return customFetch<CommitSummary[]>(getAdminListCommitsUrl(params), {
    ...options,
    method: "GET",
  });
};

